mapper.select:
SELECT
    id, parent_id, subject_id, subject_name, subject_is_other, title, description, student_gender, grade_code, available_time, teacher_gender_preference, teacher_requirement_detail, child_age, class_mode, city, address,
    frequency_per_week, budget_min, budget_max, stage_code, education_requirement, publisher_identity, schedule, biz_status, status, create_time, update_time
FROM student_job_posting
WHERE parent_id = #{parentId}

    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, parent_id, subject_id, subject_name, subject_is_other, title, description, student_gender, grade_code, available_time, teacher_gender_preference, teacher_requirement_detail, child_age, class_mode, city, address,
    frequency_per_week, budget_min, budget_max, stage_code, education_requirement, publisher_identity, schedule, biz_status, status, create_time, update_time
FROM student_job_posting
WHERE status = 1
  AND (biz_status IS NULL OR biz_status = 1)

    AND subject_id = #{subjectId}


    AND class_mode = #{classMode}


    AND city = #{city}


    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, parent_id, subject_id, subject_name, subject_is_other, title, description, student_gender, grade_code, available_time, teacher_gender_preference, teacher_requirement_detail, child_age, class_mode, city, address,
    frequency_per_week, budget_min, budget_max, stage_code, education_requirement, publisher_identity, schedule, biz_status, status, create_time, update_time
FROM student_job_posting
WHERE status = 1
  AND (biz_status IS NULL OR biz_status = 1)

    AND subject_id = #{subjectId}


    AND class_mode = #{classMode}


    AND city = #{city}


    AND (
        title LIKE CONCAT('%', #{keyword}, '%')
        OR description LIKE CONCAT('%', #{keyword}, '%')
        OR LOCATE(title, #{keyword}) > 0
        OR LOCATE(description, #{keyword}) > 0
    )


    AND id < #{cursor}



        ORDER BY budget_max DESC, id DESC


        ORDER BY id DESC


LIMIT #{pageSize}
